import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;
import java.io.IOException;
import java.util.Scanner;

public class SafePathTraversalExample {

    private static final String BASE_PATH = "C:/data/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter file name:");
        String fileName = scanner.nextLine();

        Path filePath = Paths.get(BASE_PATH, fileName).normalize().toAbsolutePath();

        if (!filePath.startsWith(Paths.get(BASE_PATH))) {
            System.out.println("Accessing files outside the allowed directory is not permitted.");
            return;
        }

        try {
            String fileContent = Files.readString(filePath);
            System.out.println(fileContent);
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

